Here's a modern MSTest test class using both `[DataRow]` and `[DynamicData]` with ValueTuples:

```csharp
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.05, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.1, DisplayName = "Negative price")]
    [DataRow(10.00, -1, 0.1, DisplayName = "Negative quantity")]
    [DataRow(10.00, 1, -0.1, DisplayName = "Negative tax")]
    [DataRow(10.00, 1, 1.5, DisplayName = "Tax > 1")]
    public void CalculateTotal_WithInvalidInputs_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for type safety ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (0m, 50m, 0m),
        (99.99m, 50m, 49.995m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0")]
    [DataRow(101.0, DisplayName = "Discount above 100")]
    public void ApplyDiscount_WithInvalidPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }
}
```

**Key patterns used:**

- **`sealed` class** — best practice for test classes
- **`[DataRow]`** — inline data for `CalculateTotal` (uses `double` since `DataRow` doesn't support `decimal` literals)
- **`[DynamicData]` with ValueTuples** — type-safe approach for `ApplyDiscount` (MSTest 3.7+), avoids `object[]` boxing
- **`Assert.ThrowsExactly<T>`** — validates exceptions without `[ExpectedException]`
- **Constructor init** — enables `readonly` fields
- **`DisplayName`** — readable test names in Test Explorer

> **Note:** `[DataRow]` only accepts compile-time constants, so `decimal` must be passed as `double` and cast. `[DynamicData]` with tuples avoids this limitation entirely.
